INSERT INTO topics (id, lang, category, title, question, answer, objections, scripture, tags, difficulty, related_topics, translation_source, last_updated)
VALUES ('cross-sign-of-cross', 'ceb', 'tradition', 'Krus ug Panguros', 'Unsa ang gitudlo sa Simbahang Katoliko bahin sa krus ug panguros?', '"ang Sta. Iglesya nagtudlo nga ang krus nagkahulogan ni Cristo ug sa atong tinuhoan. Ang pagpanguros maoy timaan sa atong pagkabinunyagan ug nga kini usa ka acto sa pagtuo tungod kay diha sa pagpanguros ato mang nga gipadayag ang atong pagtuo sa tulo ka dagkong misteryo sa atong pagtuo: ang Santisima Trinidad, sa Incarnation kun pagpakatawo sa Anak sa Dios ug sa Redemption kun pagpanubos. Ang pagpanguros usa ka acto sa pag-ampo tungod kay pinaagi niini atong gipangayo gikan sa Dios ang iyang mga panalangin. Ang pagpanguros acto usab sa pagsimba tungod kay pinaagi niini atong gihimaya ang Santisima Trinidad: Ang Amahan, ang Anak ug ang Espiritu. Ang kahulogan sa atong pagpanguros mao nga ang kasugoan sa Dios atong ibutang sa atong hunahuna, sa atong kasingkasing ug atong buhaton o ikinabuhi. Ang Simbahan naghatag og indulhensya partial sa mohimo sa panguros diha sa kahimtang sa grasya."'::jsonb, '[{"objection":"Ang krus dili angay nga pasidunggan tungod kay giingon sa Kasulatan, “tinunglo ang gibitay sa kahoy” (Gal. 3:13). Ang pagpanguros maoy patik sa mapintas nga mananap, “Gipugos sa mananap nga mapatikan ang tanang tawo, inila og dili inila, dato ug kabos, ulipon ug dili ulipon, diha sa tuo nilang kamot ug agtang” (Pin 13:16). Ang mga katoliko inay nga si Cristo maoy simbahon ang krus na hinuon ang gisimba kay diha sa ilang basahon sa pag-ampo nagkanayon, “Simbahon sa makalibo ang santos nga kahoy.” Way mabasa sa Biblia nga si Jesus nagsugo sa pagpanguros!","response":"Tinuod nga kaniadto ang krus simbolo sa pagkatinunglo tungod kay mao man kini ang bitayanan sa mga kriminal (Gal. 3:13). Apan ang plano sa Dios sa pagluwas kanato mao ang pinaagi sa iyang kamatayon didto sa krus, “Gihimo kini ni Cristo (ang pagpalansang sa krus) aron ang panalangin nga gisaad sa Dios ngadto kang Abraham ikahatag ngadto sa mga dili judio pinaagi kang Cristo Jesus, aron kita makadawat sa Espiritu nga gisaad sa Dios pinaagi sa pagtuo” (Gal. 3:14). Pinaagi sa kamatayon ni Cristo sa krus nahimo kini simbolo sa atong kaluwasan, “alang niadtong nangawala ang kaasuyan sa krus binuang, apan alang kanatong linuwas kini gahom ug kaalam sa Dios” (1 Cor. 1:18). Ang krus gigamit nga timaan sa atong pagkasumusunod ni Cristo, “Kon buot kamong mosunod kanako, pas-ana ninyo ang inyong krus matag adlaw ug sunod kanako” (Mat. 16:24). Ang krus nagpasabot usab sa pagtulon-an ni Cristo nga gisupak sa daghang mga tawo, “dunay daghang mga magtutuo kansang pagkinabuhi sukwahi sa tuyo sa kamatayon ni Cristo sa krus” (Fil. 3:18). Ang krus nagpasabot sa bag-ong kinabuhi uban ni Cristo, “Ang mga tawhanong kailibgon ug mga pangandoy gilansang na sa krus sa mga tawo nga iya na ni Cristo Jesus” (Gal. 5:24). Tungod niini si San Pablo nagpasigarbo sa krus ni Cristo ug gipatik kini diha sa iyang lawas, “Apan alang kanako magpasigarbo lamang ako sa krus sa atong Ginoong Jesu-Cristo kay pinaagi sa iyang krus patay na ang kalibotan alang kanako, ug ako patay na alang sa kalibotan… manghinaot ako nga wala na untay magsamok kanako kay ang mga ulat nga ania sa akong lawas nagmatuod nga ulipon ako ni Jesus” (Gal. 6:14, 17).\nDiha sa Daang Tugon gisugo sa Dios nga kini nga timaan ipabutang isip pagpahinumdom sa kasugoan sa Dios, “Itudlo kini sa inyong kabataan. Hisgoti kini kon anaa kamo sa inyong balay, o magpanaw kamo, o sa dayon na ninyong katulog ug sa pagmata ninyo sa buntag. Ibugkos kini sa inyong kamot ingon nga ilhanan ug ibutang ingon nga timaan diha sa inyong agtang. Isulat kini diha sa haligi sa pultahan sa inyong balay ug diha sa inyong mga ganghaan” (Deut. 6:6-9). Ang Dios nagsugo sa pagpapatay sa tanang mga molupyo sa usa ka dapit apan ang dunay timaan sa krus wala niya ipaapil, “Sulod kamo kaniya ug pamatya ninyo sa walay kukaluoy ang mga molupyo sa siyudad. Pamatya ang mga tigulang ug ang mga batan-on ingon man ang kabataan ug kababayen-an, apan ayaw ilakip pagpatay kadtong may patik (tau = krus) sa ilang agtang” (Eze. 9:5-6). Ang krus magamit usab nga timaan sa mga lubong nga ang namatay usa ka magtutuo, “Sama kamo sa lubong nga walay timaan, nga wala lamang hibaloi sa mga tawo nga ila diayng gitamakan” (Luc. 11:44). Ang krus mao ang timaan sa Anak sa tawo nga mopasiuna pagpakita sa iyang ikaduhang pagbalik, “Unya motungha sa langit ang timaan sa Anak sa Tawo” (Mat. 24:20). Mahitungod sa panguros, ang mga linuwas gipatik diha sa ilang agtang ang ngalan sa Amahan og sa Anak, “kansang mga agtang gisulatan sa iyang ngalan ug sa ngalan sa iyang Amahan” (Pin. 14:1), “Makakita sila sa nawong niya ug ang iyang ngalan isulat diha sa ilang agtang” (Pin. 22:4). Ang Espiritu Santo ipatik usab, “Busa gipatikan kamo sa Dios pinaagi sa paghatag kaninyo sa Espiritu Santo” (Efeso 1:13); “kay ang Espiritu mao ang patik sa Dios diha kaninyo ilhanan nga kamo iya na, ug garantiya nga moabot ang adlaw nga luwason kamo sa Dios” (Efeso 4:30).\nDugang mga tubag: Ang gipatik diha sa Pin. 13:16 mao ang ngalan sa mapintas nga mananap, “Walay makapamalit ug makapamaligya gawas niadtong may patik sa ngalan sa mananap” (Pin 13:17) apan diha sa pagpanguros ang ipatik mao ang ngalan sa Amahan, ug sa Anak ug sa Espiritu Santo (Mat. 28:19) busa dili kini motukma. Ang pag-ampo nga nagkanayon, “Simbahon sa makalibo ang santos nga kahoy” usa kini ka hulad pamulong nga gitawag og metonymy nga ang ranggo, titulo, kahimtang ug kabtangan ang gigamit sa pagpahayag nga mao ang nanag-iya sa maong nahisgotan sa unahan sama pananglit sa pag-ingon nga “nailog ang korona sa hari” nga nagpasabot sa hari nga nabuntog. Sa Kasulatan ang Dios miingon, “tahora ninyo ang akong sanctuario” (Lev. 19:30); ang ipatahod dinhi mao nga sanctuario nga nagpasabot sa Dios nga nagpuyo diha sa iyang sanctuario. “Dayga ninyo ang Dios ug simbaha ang iyang tumbanan kay kini balaan” (Sal. 99:5). Ang ipasimba dinhi mao ang tumbanan apan nagpasabot kini sa Dios nga nagtunob. Busa ang pag-ingon nga “simbahon ang krus” ang gipasabot niini mao si Cristo nga gilansang diha sa krus. Tinuod nga wala kitay mabasa letra por letra diha sa Biblia nga si Jesus nagsugo sa pagpanguros apan angay usab nato nga timan-an ang gisulti ni San Juan, “may daghan pang butang nga gibuhat si Jesus nga wala masulat niining basahona” (Jn. 21:25). Ang pagpanguros usa ka balansayon sa unang mga kristyanos nga atong nadawat gikan sa Tradisyon kun mga pagtulon-an sa mga Apostoles nga binaba. Ang kasaysayan nagtudlo kanato sa kakaraan niining maong balansayon nga naggikan sa mga Apostoles, “Ang unang mga pagbansay sa Karaang Iglesya. Ang timaan sa krus ug ang pagtahod sa lawas sa mga martir… nagsukad sa karaang kaayong panahon… sukad sa panahon sa mga apostoles” (World History by Obrien p. 146). Usa ka nabantog nga hitabo sa kasaysayan mao ang kang Emperador Constantino nga sa dihang nagpaingon siya sa gubat nakakita siyag panan-awon sa langit sa timaan sa krus ug sa mga pulong “In hoc signo vinces” nga ang hubad niini: niini nga timaan ikaw modaug. Busa gipabutangan ni Constantino ang mga taming sa iyang sundalo sa timaan sa krus ug niadtong adlaw nagmadaugon si Constantino batok kang Maxentius ug mao kadto ang sinugdanan sa paghunong sa pagpanglutos batok sa mga kristyanos. Giingon pa gayod sa laing karaang sugid nga sa panahon ni Rayna Helena nga inahan ni Constantino nga nakaplagan nila ang duha ka krus ug ilang gituohan nga usa niadto mao ang krus ni Cristo. Busa aron pag-ila sa matuod nga krus sa atong Ginoo ilang gibutang ang usa ka minatay duol sa usa ka krus ug kini nabuhi ug pinaagi niadto ilang nailhan ang krus ni Cristo."}]'::jsonb, '["Gal. 3:13","Pin 13:16","Gal. 3:14","1 Cor. 1:18","Mat. 16:24","Fil. 3:18","Gal. 5:24","Gal. 6:14, 17","Deut. 6:6-9","Eze. 9:5-6","Luc. 11:44","Mat. 24:20","Pin. 14:1","Pin. 22:4","Efeso 1:13","Efeso 4:30","Pin 13:17","Lev. 19:30","Sal. 99:5","Jn. 21:25"]'::jsonb, '["cross sign of cross"]'::jsonb, 'beginner', '[]'::jsonb, 'manual', '2026-07-23T08:13:34.048Z')
